Executando comando: cd /home/ubuntu && cat >> server/routers-stripe.ts << 'EOF'

  /**
   * Criar payment intent para pagamento com cartao
   */
  createPaymentIntent: protectedProcedure
    .input((val: any) => ({
      planId: typeof val?.planId === "number" ? val.planId : 0,
      billingCycle: ["monthly", "yearly"].includes(val?.billingCycle)
        ? val.billingCycle
        : "monthly",
      amount: typeof val?.amount === "number" ? val.amount : 0,
      paymentMethodId: typeof val?.paymentMethodId === "string" ? val.paymentMethodId : "",
    }))
    .mutation(async ({ input, ctx }) => {
      const db = await getDb();
      if (!db) {
        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Database not available",
        });
      }

      if (!input.planId || !input.amount) {
        throw new TRPCError({
          code: "BAD_REQUEST",
          message: "Plan ID and amount are required",
        });
      }

      try {
        // Get plan details
        const planResult = await db
          .select()
          .from(plans)
          .where(eq(plans.id, input.planId))
          .limit(1);

        if (!planResult.length) {
          throw new TRPCError({
            code: "NOT_FOUND",
            message: "Plan not found",
          });
        }

        const plan = planResult[0];

        // Create payment intent
        const paymentIntent = await stripe.paymentIntents.create({
          amount: input.amount,
          currency: "brl",
          payment_method: input.paymentMethodId,
          confirm: true,
          automatic_payment_methods: {
            enabled: true,
            allow_redirects: "never",
          },
          metadata: {
            userId: ctx.user.id.toString(),
            planId: input.planId.toString(),
            billingCycle: input.billingCycle,
            planName: plan.name,
          },
          receipt_email: ctx.user.email || undefined,
        });

        return {
          clientSecret: paymentIntent.client_secret,
          paymentIntentId: paymentIntent.id,
          status: paymentIntent.status,
        };
      } catch (error: any) {
        console.error("[Stripe] Error creating payment intent:", error);

        // Handle specific Stripe errors
        if (error.type === "StripeCardError") {
          throw new TRPCError({
            code: "BAD_REQUEST",
            message: error.message || "Erro no cartao",
          });
        }

        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: error.message || "Failed to create payment intent",
        });
      }
    }),
});
EOF

