  /**
   * Obter assinaturas do usuario
   */
  getUserSubscriptions: protectedProcedure
    .input((val: any) => ({
      userId: typeof val?.userId === "number" ? val.userId : 0,
    }))
    .query(async ({ input, ctx }) => {
      const db = await getDb();
      if (!db) {
        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Database not available",
        });
      }

      // Ensure user can only see their own subscriptions
      if (input.userId !== ctx.user.id) {
        throw new TRPCError({
          code: "FORBIDDEN",
          message: "You can only view your own subscriptions",
        });
      }

      try {
        const userSubscriptions = await db
          .select({
            id: subscriptions.id,
            planId: subscriptions.planId,
            planName: plans.name,
            amount: plans.priceMonthly,
            status: subscriptions.status,
            billingCycle: "monthly",
            startedAt: subscriptions.startedAt,
            expiresAt: subscriptions.expiresAt,
            autoRenew: subscriptions.autoRenew,
            paymentMethod: subscriptions.paymentMethod,
          })
          .from(subscriptions)
          .innerJoin(plans, eq(subscriptions.planId, plans.id))
          .where(eq(subscriptions.userId, input.userId))
          .orderBy(subscriptions.createdAt);

        return userSubscriptions;
      } catch (error) {
        console.error("[Stripe] Error fetching user subscriptions:", error);
        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Failed to fetch subscriptions",
        });
      }
    }),
});
ENDPOINT

