import { TRPCError } from "@trpc/server";
import PDFDocument from "pdfkit";

/**
 * Invoice Service - Gera faturas em PDF
 */

interface InvoiceData {
  invoiceId: number;
  userId: number;
  userName: string;
  userEmail: string;
  planName: string;
  amount: number;
  billingCycle: string;
  issuedAt: Date;
  dueAt: Date;
  paidAt: Date | null;
  status: "pending" | "paid" | "failed" | "refunded";
}

/**
 * Gerar fatura em PDF
 */
export async function generateInvoicePDF(data: InvoiceData): Promise<Buffer> {
  return new Promise((resolve, reject) => {
    try {
      const doc = new PDFDocument({
        size: "A4",
        margin: 50,
      });

      const chunks: Buffer[] = [];

      doc.on("data", (chunk: Buffer) => {
        chunks.push(chunk);
      });

      doc.on("end", () => {
        resolve(Buffer.concat(chunks));
      });

      doc.on("error", (error: Error) => {
        reject(error);
      });

      // Header
      doc.fontSize(24).font("Helvetica-Bold").text("FATURA", { align: "center" });
      doc.moveDown(0.5);
      doc.fontSize(10).font("Helvetica").text("Propaga Digital", { align: "center" });
      doc.text("propaga.digital@example.com", { align: "center" });
      doc.moveDown(1);

      // Invoice Number & Date
      doc.fontSize(10).font("Helvetica");
      doc.text(`Número da Fatura: ${data.invoiceId}`, 50, 150);
      doc.text(`Data de Emissão: ${formatDate(data.issuedAt)}`, 50, 170);
      doc.text(`Data de Vencimento: ${formatDate(data.dueAt)}`, 50, 190);

      // Status
      const statusColor = data.status === "paid" ? "#22C55E" : "#EF4444";
      doc.rect(300, 150, 200, 60).fill(statusColor);

      doc
        .fontSize(12)
        .font("Helvetica-Bold")
        .fillColor(statusColor)
        .text(getStatusLabel(data.status).toUpperCase(), 310, 170, {
          align: "center",
        });

      doc.fillColor("#000000");
      doc.moveDown(2);

      // Customer Info
      doc.fontSize(10).font("Helvetica-Bold").text("CLIENTE");
      doc.fontSize(10).font("Helvetica");
      doc.text(data.userName);
      doc.text(data.userEmail);
      doc.moveDown(1);

      // Invoice Details Table
      const tableTop = 320;
      const tableLeft = 50;
      const tableWidth = 495;
      const rowHeight = 30;

      // Table Header
      doc.rect(tableLeft, tableTop, tableWidth, rowHeight).fill("#D4AF37");

      doc
        .fontSize(10)
        .font("Helvetica-Bold")
        .fillColor("#000000")
        .text("Descrição", tableLeft + 10, tableTop + 8)
        .text("Ciclo", tableLeft + 250, tableTop + 8)
        .text("Valor", tableLeft + 350, tableTop + 8)
        .text("Total", tableLeft + 420, tableTop + 8);

      // Table Row
      const rowTop = tableTop + rowHeight;
      doc.rect(tableLeft, rowTop, tableWidth, rowHeight).stroke("#D4AF37");

      doc
        .fontSize(10)
        .font("Helvetica")
        .fillColor("#000000")
        .text(data.planName, tableLeft + 10, rowTop + 8)
        .text(formatBillingCycle(data.billingCycle), tableLeft + 250, rowTop + 8)
